### TanStack Query (React Query)

TanStack Query is a data-fetching and caching library for React. It manages server state including caching, background refetching, pagination, and optimistic updates.

---

### Installation

```bash
npm install @tanstack/react-query
```

### Setup Provider

```jsx
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';

const queryClient = new QueryClient();

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <YourApp />
    </QueryClientProvider>
  );
}
```

### Basic Query

```jsx
import { useQuery } from '@tanstack/react-query';

function UserProfile({ userId }) {
  const { data, isLoading, error } = useQuery({
    queryKey: ['user', userId],
    queryFn: () => fetch(`/api/users/${userId}`).then(r => r.json()),
  });

  if (isLoading) return <Spinner />;
  if (error) return <Error message={error.message} />;
  return <h1>{data.name}</h1>;
}
```

### Mutations

```jsx
import { useMutation, useQueryClient } from '@tanstack/react-query';

function AddTodo() {
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: (newTodo) => fetch('/api/todos', {
      method: 'POST',
      body: JSON.stringify(newTodo),
    }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['todos'] });
    },
  });

  return (
    <button onClick={() => mutation.mutate({ title: 'New Task' })}>
      Add Todo
    </button>
  );
}
```

### Key Features

| Feature | Description |
|---------|-------------|
| Caching | Automatic in-memory cache |
| Background refetch | Stale data refreshes automatically |
| Pagination | Built-in infinite queries |
| Optimistic updates | Update UI before server confirms |
| Retry | Automatic retry on failure |
| DevTools | Query devtools for debugging |

> **Key Point:** TanStack Query replaces manual useEffect fetch patterns. It handles caching, loading states, error handling, and refetching automatically. Use it for all server state in your React applications.

codeExample:
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

function TodoApp() {
  const queryClient = useQueryClient();

  const { data: todos } = useQuery({
    queryKey: ['todos'],
    queryFn: () => fetch('/api/todos').then(r => r.json()),
  });

  const deleteMutation = useMutation({
    mutationFn: (id) => fetch(`/api/todos/${id}`, { method: 'DELETE' }),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['todos'] }),
  });

  return todos?.map(todo => (
    <div key={todo.id}>
      <span>{todo.title}</span>
      <button onClick={() => deleteMutation.mutate(todo.id)}>Delete</button>
    </div>
  ));
}
